import axios from 'axios';

// Configure base URL for your backend API
const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:3001/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  timeout: 30000, // 30 seconds timeout for file uploads
});

// Mock data for demonstration (remove when connecting to real backend)
const mockDetectedItems = [
  {
    name: 'Wooden Chair',
    category: 'Furniture',
    material: 'Wood',
    confidence: 0.95
  },
  {
    name: 'LED Light',
    category: 'Lighting',
    material: 'Electrical',
    confidence: 0.88
  },
  {
    name: 'Fabric Curtain',
    category: 'Decor',
    material: 'Fabric',
    confidence: 0.92
  },
  {
    name: 'Metal Stand',
    category: 'Furniture',
    material: 'Metal',
    confidence: 0.85
  }
];

export const fetchDetectedItems = async (file) => {
  try {
    // For demo purposes, return mock data after a delay
    // Replace this with actual API call when backend is ready
    await new Promise(resolve => setTimeout(resolve, 2000));
    
    // Uncomment and modify this when connecting to real backend:
    /*
    const formData = new FormData();
    formData.append('file', file);
    
    const response = await api.post('/analyze', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    });
    
    return response.data.items || [];
    */
    
    return mockDetectedItems;
  } catch (error) {
    console.error('Error fetching detected items:', error);
    throw new Error('Failed to analyze file');
  }
};

export const uploadFile = async (file) => {
  try {
    const formData = new FormData();
    formData.append('file', file);
    
    const response = await api.post('/upload', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    });
    
    return response.data;
  } catch (error) {
    console.error('Error uploading file:', error);
    throw new Error('Failed to upload file');
  }
};

export default api;
